from typing import Optional, Tuple, List

_VALID_CHANNELS = {"alpha", "beta", "gamma"}
_VALID_VERSIONS = {1, 2, 3}
_CHECKSUM_MODULUS = {1: 89, 2: 97, 3: 113}
_CHANNEL_NORMALIZER = {"alpha": 100.0, "beta": 10.0, "gamma": 1.0}
_TOKEN_PATTERN = re.compile(r"^[A-Z][0-9]$")


def solve(packet: str) -> float:
    try:
        parsed = _parse_packet(packet)
        if parsed is None:
            return -1.0

        version, channel, payload, checksum = parsed

        if version not in _VALID_VERSIONS or channel not in _VALID_CHANNELS:
            return -1.0

        tokens = payload.split("-")
        if not tokens or any(not _TOKEN_PATTERN.fullmatch(t) for t in tokens):
            return -1.0

        for raw_sum in _possible_token_sums(tokens):
            if raw_sum % _CHECKSUM_MODULUS[version] == checksum:
                return float(raw_sum / _CHANNEL_NORMALIZER[channel])

        return -1.0
    except Exception:
        return -1.0


def _parse_packet(packet: str) -> Optional[Tuple[int, str, str, int]]:
    if not isinstance(packet, str):
        return None

    s = packet.strip()
    if not s:
        return None

    kv = _parse_key_value_packet(s)
    if kv is not None:
        return kv

    candidates: List[List[str]] = []

    if "#" in s:
        left, right = s.rsplit("#", 1)
        for delim in ("|", ":", ";", ",", "/"):
            parts = [p.strip() for p in left.split(delim)]
            if len(parts) == 3:
                candidates.append(parts + [right.strip()])

    for delim in ("|", ":", ";", ",", "/"):
        parts = [p.strip() for p in s.split(delim)]
        if len(parts) == 5 and parts[0].lower() in {"fluxon", "packet", "fx"}:
            parts = parts[1:]
        if len(parts) == 4:
            candidates.append(parts)

    for parts in candidates:
        parsed = _interpret_fields(parts)
        if parsed is not None:
            return parsed

    return None


def _parse_key_value_packet(s: str) -> Optional[Tuple[int, str, str, int]]:
    normalized = s
    for sep in (";", "|", ",", "&"):
        normalized = normalized.replace(sep, ";")

    fields = {}
    for item in normalized.split(";"):
        if "=" not in item:
            continue
        key, value = item.split("=", 1)
        key = key.strip().lower()
        value = value.strip()
        if key in {"v", "ver", "version"}:
