    for index, token in enumerate(_split_fluxon_payload(payload), start=1):
        if not _TOKEN_PATTERN.match(token):
            raise ValueError(f"Invalid token: {token!r}")
        letter_value = ord(token[0]) - ord("A") + 1
        digit_value = int(token[1])
        total += index * (letter_value + digit_value)

    return total % moduli[version]


