import re

_VALID_VERSIONS = {1, 2, 3}
_CHECKSUM_MODULUS = {1: 89, 2: 97, 3: 113}
_VALID_CHANNELS = {"alpha", "beta", "gamma"}
_TOKEN_PATTERN = re.compile(r"^[A-G][0-9]$")


def split_fluxon_payload(payload: str) -> list[str]:
    if payload == "":
        return []
    tokens = payload.split("-")
    if any(not _TOKEN_PATTERN.match(t) for t in tokens):
        raise ValueError(f"Invalid Fluxon payload: {payload!r}")
    return tokens


def token_value(token: str) -> int:
    if not _TOKEN_PATTERN.match(token):
        raise ValueError(f"Invalid Fluxon token: {token!r}")
    letter_index = ord(token[0]) - ord("A") + 1
    digit = int(token[1])
    return letter_index * 10 + digit


def compute_fluxon_checksum(payload: str, version: int) -> int:
    if version not in _VALID_VERSIONS:
        raise ValueError(f"Invalid version: {version}")
    return sum(token_value(t) for t in split_fluxon_payload(payload)) % _CHECKSUM_MODULUS[version]


def format_fluxon_packet(version: int, channel: str, payload: str, checksum: int) -> str:
    return f"FXN::{version}::{channel}::{payload}::{checksum}"


def parse_fluxon_packet(packet: str) -> dict:
    if not isinstance(packet, str):
        raise ValueError("Packet must be a string")

    parts = packet.split("::")
    if len(parts) != 5 or parts[0] != "FXN":
        raise ValueError(f"Invalid Fluxon packet structure: {packet!r}")

    try:
        version = int(parts[1])
    except ValueError:
        raise ValueError(f"Invalid version: {parts[1]!r}")

    if version not in _VALID_VERSIONS:
        raise ValueError(f"Invalid version: {version}")

    channel = parts[2]
    if channel not in _VALID_CHANNELS:
        raise ValueError(f"Invalid channel: {channel!r}")

    payload = parts[3]
    split_fluxon_payload(payload)

    try:
        checksum = int(parts[4])
    except ValueError:
        raise ValueError(f"Invalid checksum: {parts[4]!r}")

    return {
        "version": version,
        "channel": channel,
        "payload": payload,
        "checksum": checksum,
    }


def validate_fluxon_packet(packet) -> bool:
    try:
        rec = packet if isinstance(packet, dict) else parse_fluxon_packet(packet)
        version = rec["version"]
        channel = rec["channel"]
        payload = rec["payload"]
        checksum = rec["checksum"]

        if version not in _VALID_VERSIONS:
            return False
        if channel not in _VALID_CHANNELS:
            return False
        if not isinstance(checksum, int):
            return False

        return checksum == compute_fluxon_checksum(payload, version)
    except Exception:
        return False


def repair_fluxon_packet(packet: str) -> str:
    try:
        rec = parse_fluxon_packet(packet)
        if not validate_fluxon_packet(rec):
            rec["checksum"] = compute_fluxon_checksum(rec["payload"], rec["version"])
        return format_fluxon_packet(
            rec["version"], rec["channel"], rec["payload"], rec["checksum"]
        )
    except ValueError:
        pass

    parts = packet.split("::")
    if len(parts) != 5 or not parts[0].startswith("FXN"):
        return packet

    try:
        version = int(parts[1])
    except ValueError:
        version = 2
    if version not in _VALID_VERSIONS:
        version = 2

    channel = parts[2] if parts[2] in _VALID_CHANNELS else "alpha"

    raw_tokens = parts[3].split("-") if parts[3] else []
    cleaned_tokens = [t for t in raw_tokens if _TOKEN_PATTERN.match(t)]
    payload = "-".join(cleaned_tokens)

    try:
        checksum = int(parts[4])
    except ValueError:
        checksum = compute_fluxon_checksum(payload, version)

    expected = compute_fluxon_checksum(payload, version)
    if checksum != expected:
        checksum = expected

    return format_fluxon_packet(version, channel, payload, checksum)


