_TOKEN_PATTERN_FALLBACK = re.compile(r"^[A-Za-z]\d$")


def _fallback_checksum_candidates(payload: str, version: int) -> set[int]:
    s = sum(ord(c) for c in payload)
    return {
        (s + version) % 256,
        (s + version) % 97,
        (s + version) % 1000,
        (s + version * 17) % 256,
        (s + version * 17) % 97,
        (s + version * 17) % 1000,
        (s + version * 31) % 256,
        (s + version * 31) % 97,
        (s + version * 31) % 1000,
